// Harness: background execution -- the model thinks while the harness waits.
/*
s08_background_tasks.ts- Background Tasks

Run commands in background threads. A notification queue is drained
before each LLM call to deliver results.

    Main thread                Background thread
    +-----------------+        +-----------------+
    | agent loop      |        | task executes   |
    | ...             |        | ...             |
    | [LLM call]  <---+------- | enqueue(result) |
    |  ^drain queue   |        +-----------------+
    +-----------------+

    Timeline:
    Agent ----[spawn A]----[spawn B]----[other work]----
                  |              |
                  v              v
              [A runs]      [B runs]        (parallel)
                  |              |
                  +-- notification queue --> [results injected]

Key insight: "Fire and forget -- the agent doesn't block while the command runs."
 */

import Anthropic from "@anthropic-ai/sdk";
import { config as loadEnv } from "dotenv";
import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { spawnSync } from "node:child_process";
import { randomUUID } from "node:crypto";
import { resolve, dirname, relative } from "node:path";
import { createInterface } from "node:readline/promises";
import { stdin as input, stdout as output } from "node:process";

loadEnv({ override: true, quiet: true });

if (process.env.ANTHROPIC_BASE_URL) {
  delete process.env.ANTHROPIC_AUTH_TOKEN;
}

const WORKDIR = resolve(process.cwd());
const MODEL = process.env.MODEL_ID ?? "claude-sonnet-4-20250514";
const SYSTEM = `You are a coding agent at ${WORKDIR}. Use background_run for long-running commands.`;
const DANGEROUS_COMMANDS = ["rm -rf /", "sudo", "shutdown", "reboot", "> /dev/"];

const client = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
  baseURL: process.env.ANTHROPIC_BASE_URL || undefined,
});

// -- BackgroundManager: threaded execution + notification queue --
class BackgroundManager {
  tasks: Record<string, { status: string; result: string | null; command: string }>;
  notificationQueue: Array<{ task_id: string; status: string; command: string; result: string }>;

  constructor() {
    this.tasks = {};
    this.notificationQueue = [];
  }

  run(command: string): string {
    const taskId = randomUUID().slice(0, 8);
    this.tasks[taskId] = { status: "running", result: null, command };
    setTimeout(() => this.execute(taskId, command), 0);
    return `Background task ${taskId} started: ${command.slice(0, 80)}`;
  }

  execute(taskId: string, command: string): void {
    let output = "";
    let status = "completed";
    try {
      const result = spawnSync(command, {
        shell: true,
        cwd: WORKDIR,
        encoding: "utf8",
        timeout: 300_000,
      });
      output = `${result.stdout ?? ""}${result.stderr ?? ""}`.trim().slice(0, 50_000);
      if (result.error && (result.error as NodeJS.ErrnoException).code === "ETIMEDOUT") {
        output = "Error: Timeout (300s)";
        status = "timeout";
      } else if (result.error) {
        output = `Error: ${result.error instanceof Error ? result.error.message : String(result.error)}`;
        status = "error";
      }
    } catch (error) {
      output = `Error: ${error instanceof Error ? error.message : String(error)}`;
      status = "error";
    }

    this.tasks[taskId].status = status;
    this.tasks[taskId].result = output || "(no output)";
    this.notificationQueue.push({
      task_id: taskId,
      status,
      command: command.slice(0, 80),
      result: (output || "(no output)").slice(0, 500),
    });
  }

  check(taskId?: string): string {
    if (taskId) {
      const task = this.tasks[taskId];
      if (!task) {
        return `Error: Unknown task ${taskId}`;
      }
      return `[${task.status}] ${task.command.slice(0, 60)}\n${task.result ?? "(running)"}`;
    }
    const lines = Object.entries(this.tasks).map(([id, task]) => `${id}: [${task.status}] ${task.command.slice(0, 60)}`);
    return lines.length ? lines.join("\n") : "No background tasks.";
  }

  drainNotifications(): Array<{ task_id: string; status: string; command: string; result: string }> {
    const notifications = [...this.notificationQueue];
    this.notificationQueue = [];
    return notifications;
  }
}

const BG = new BackgroundManager();

// -- Tool implementations --
function safePath(filePath: string): string {
  const absolute = resolve(WORKDIR, filePath);
  const rel = relative(WORKDIR, absolute);
  if (rel.startsWith("..")) {
    throw new Error(`Path escapes workspace: ${filePath}`);
  }
  return absolute;
}

function runBash(command: string): string {
  if (DANGEROUS_COMMANDS.some((token) => command.includes(token))) {
    return "Error: Dangerous command blocked";
  }
  const result = spawnSync(command, {
    shell: true,
    cwd: WORKDIR,
    encoding: "utf8",
    timeout: 120_000,
  });
  if (result.error) {
    if ((result.error as NodeJS.ErrnoException).code === "ETIMEDOUT") {
      return "Error: Timeout (120s)";
    }
    return `Error: ${result.error instanceof Error ? result.error.message : String(result.error)}`;
  }
  const text = `${result.stdout ?? ""}${result.stderr ?? ""}`.trim();
  return text.slice(0, 50_000) || "(no output)";
}

function runRead(filePath: string, limit?: number): string {
  try {
    const lines = readFileSync(safePath(filePath), "utf8").split(/\r?\n/);
    if (limit && limit < lines.length) {
      const remaining = lines.length - limit;
      return [...lines.slice(0, limit), `... (${remaining} more)`].join("\n").slice(0, 50_000);
    }
    return lines.join("\n").slice(0, 50_000);
  } catch (error) {
    return `Error: ${error instanceof Error ? error.message : String(error)}`;
  }
}

function runWrite(filePath: string, content: string): string {
  try {
    const absolute = safePath(filePath);
    mkdirSync(dirname(absolute), { recursive: true });
    writeFileSync(absolute, content, "utf8");
    return `Wrote ${content.length} bytes`;
  } catch (error) {
    return `Error: ${error instanceof Error ? error.message : String(error)}`;
  }
}

function runEdit(filePath: string, oldText: string, newText: string): string {
  try {
    const absolute = safePath(filePath);
    const content = readFileSync(absolute, "utf8");
    if (!content.includes(oldText)) {
      return `Error: Text not found in ${filePath}`;
    }
    writeFileSync(absolute, content.replace(oldText, newText), "utf8");
    return `Edited ${filePath}`;
  } catch (error) {
    return `Error: ${error instanceof Error ? error.message : String(error)}`;
  }
}

const TOOL_HANDLERS = {
  bash: (input: Record<string, unknown>) => runBash(String(input.command ?? "")),
  read_file: (input: Record<string, unknown>) =>
    runRead(String(input.path ?? ""), Number(input.limit || 0) || undefined),
  write_file: (input: Record<string, unknown>) =>
    runWrite(String(input.path ?? ""), String(input.content ?? "")),
  edit_file: (input: Record<string, unknown>) =>
    runEdit(
      String(input.path ?? ""),
      String(input.old_text ?? ""),
      String(input.new_text ?? "")
    ),
  background_run: (input: Record<string, unknown>) => BG.run(String(input.command ?? "")),
  check_background: (input: Record<string, unknown>) =>
    BG.check(input.task_id ? String(input.task_id) : undefined),
};

const TOOLS = [
  {
    name: "bash",
    description: "Run a shell command (blocking).",
    input_schema: {
      type: "object",
      properties: { command: { type: "string" } },
      required: ["command"],
    },
  },
  {
    name: "read_file",
    description: "Read file contents.",
    input_schema: {
      type: "object",
      properties: {
        path: { type: "string" },
        limit: { type: "integer" },
      },
      required: ["path"],
    },
  },
  {
    name: "write_file",
    description: "Write content to file.",
    input_schema: {
      type: "object",
      properties: {
        path: { type: "string" },
        content: { type: "string" },
      },
      required: ["path", "content"],
    },
  },
  {
    name: "edit_file",
    description: "Replace exact text in file.",
    input_schema: {
      type: "object",
      properties: {
        path: { type: "string" },
        old_text: { type: "string" },
        new_text: { type: "string" },
      },
      required: ["path", "old_text", "new_text"],
    },
  },
  {
    name: "background_run",
    description: "Run command in background thread. Returns task_id immediately.",
    input_schema: {
      type: "object",
      properties: { command: { type: "string" } },
      required: ["command"],
    },
  },
  {
    name: "check_background",
    description: "Check background task status. Omit task_id to list all.",
    input_schema: {
      type: "object",
      properties: { task_id: { type: "string" } },
    },
  },
];

async function agentLoop(
  messages: Array<{ role: "user" | "assistant"; content: unknown }>
): Promise<void> {
  while (true) {
    // Drain background notifications and inject as system message before LLM call
    const notifications = BG.drainNotifications();
    if (notifications.length && messages.length) {
      const notificationText = notifications
        .map((item) => `[bg:${item.task_id}] ${item.status}: ${item.result}`)
        .join("\n");
      messages.push({
        role: "user",
        content: `<background-results>\n${notificationText}\n</background-results>`,
      });
      messages.push({ role: "assistant", content: "Noted background results." });
    }

    const response = await client.messages.create({
      model: MODEL,
      system: SYSTEM,
      messages: messages as never,
      tools: TOOLS as never,
      max_tokens: 8000,
    });

    messages.push({
      role: "assistant",
      content: response.content,
    });

    if (response.stop_reason !== "tool_use") {
      return;
    }

    const results: Array<Record<string, unknown>> = [];
    for (const block of response.content as unknown[]) {
      if (
        !block ||
        typeof block !== "object" ||
        (block as { type?: string }).type !== "tool_use"
      ) {
        continue;
      }

      const toolBlock = block as {
        id: string;
        name: keyof typeof TOOL_HANDLERS | string;
        input: Record<string, unknown>;
      };

      let output = "";
      try {
        const handler = TOOL_HANDLERS[toolBlock.name as keyof typeof TOOL_HANDLERS];
        output = handler ? handler(toolBlock.input) : `Unknown tool: ${toolBlock.name}`;
      } catch (error) {
        output = `Error: ${error instanceof Error ? error.message : String(error)}`;
      }

      console.log(`> ${toolBlock.name}: ${String(output).slice(0, 200)}`);
      results.push({
        type: "tool_result",
        tool_use_id: toolBlock.id,
        content: String(output),
      });
    }
    messages.push({ role: "user", content: results });
  }
}

const history: Array<{ role: "user" | "assistant"; content: unknown }> = [];
const rl = createInterface({ input, output });

try {
  while (true) {
    const query = await rl.question("\u001b[36ms08 >> \u001b[0m");
    const trimmed = query.trim();
    if (!trimmed || trimmed.toLowerCase() === "q" || trimmed.toLowerCase() === "exit") {
      break;
    }

    history.push({ role: "user", content: query });
    await agentLoop(history);

    const responseContent = history[history.length - 1]?.content;
    if (Array.isArray(responseContent)) {
      console.log(responseContent.map((block) => (block as { text?: string }).text ?? "").join(""));
    }
    console.log();
  }
} finally {
  rl.close();
}

// Harness: team mailboxes -- multiple models, coordinated through files.
/*
s09_agent_teams.ts- Agent Teams

Persistent named agents with file-based JSONL inboxes. Each teammate runs
its own agent loop in a separate thread. Communication via append-only inboxes.

    Subagent (s04):  spawn -> execute -> return summary -> destroyed
    Teammate (s09):  spawn -> work -> idle -> work -> ... -> shutdown

    .team/config.json                   .team/inbox/
    +----------------------------+      +------------------+
    | {"team_name": "default",   |      | alice.jsonl      |
    |  "members": [              |      | bob.jsonl        |
    |    {"name":"alice",        |      | lead.jsonl       |
    |     "role":"coder",        |      +------------------+
    |     "status":"idle"}       |
    |  ]}                        |      send_message("alice", "fix bug"):
    +----------------------------+        open("alice.jsonl", "a").write(msg)

                                        read_inbox("alice"):
    spawn_teammate("alice","coder",...)   msgs = [json.loads(l) for l in ...]
          |                                open("alice.jsonl", "w").close()
          v                                return msgs  # drain
    Thread: alice             Thread: bob
    +------------------+      +------------------+
    | agent_loop       |      | agent_loop       |
    | status: working  |      | status: idle     |
    | ... runs tools   |      | ... waits ...    |
    | status -> idle   |      |                  |
    +------------------+      +------------------+

    5 message types (all declared, not all handled here):
    +-------------------------+-----------------------------------+
    | message                 | Normal text message               |
    | broadcast               | Sent to all teammates             |
    | shutdown_request        | Request graceful shutdown (s10)   |
    | shutdown_response       | Approve/reject shutdown (s10)     |
    | plan_approval_response  | Approve/reject plan (s10)         |
    +-------------------------+-----------------------------------+

Key insight: "Teammates that can talk to each other."
 */

import Anthropic from "@anthropic-ai/sdk";
import { config as loadEnv } from "dotenv";
import {
  appendFileSync,
  existsSync,
  mkdirSync,
  readFileSync,
  writeFileSync,
} from "node:fs";
import { spawnSync } from "node:child_process";
import { dirname, join, relative, resolve } from "node:path";
import { createInterface } from "node:readline/promises";
import { stdin as input, stdout as output } from "node:process";

loadEnv({ override: true, quiet: true });

if (process.env.ANTHROPIC_BASE_URL) {
  delete process.env.ANTHROPIC_AUTH_TOKEN;
}

const WORKDIR = resolve(process.cwd());
const client = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
  baseURL: process.env.ANTHROPIC_BASE_URL || undefined,
});
const MODEL = process.env.MODEL_ID ?? "claude-sonnet-4-20250514";
const TEAM_DIR = join(WORKDIR, ".team");
const INBOX_DIR = join(TEAM_DIR, "inbox");

const SYSTEM = `You are a team lead at ${WORKDIR}. Spawn teammates and communicate via inboxes.`;

const VALID_MSG_TYPES = [
  "message",
  "broadcast",
  "shutdown_request",
  "shutdown_response",
  "plan_approval_response",
] as const;

type MessageType = (typeof VALID_MSG_TYPES)[number];

// -- MessageBus: JSONL inbox per teammate --
class MessageBus {
  dir: string;

  constructor(inbox_dir: string) {
    this.dir = inbox_dir;
    mkdirSync(this.dir, { recursive: true });
  }

  send(
    sender: string,
    to: string,
    content: string,
    msg_type: MessageType | string = "message",
    extra: Record<string, unknown> | null = null
  ): string {
    if (!VALID_MSG_TYPES.includes(msg_type as MessageType)) {
      return `Error: Invalid type '${msg_type}'. Valid: ${VALID_MSG_TYPES.join(", ")}`;
    }
    const msg: Record<string, unknown> = {
      type: msg_type,
      from: sender,
      content,
      timestamp: Date.now() / 1000,
    };
    if (extra) {
      Object.assign(msg, extra);
    }
    const inbox_path = join(this.dir, `${to}.jsonl`);
    appendFileSync(inbox_path, `${JSON.stringify(msg)}\n`, "utf8");
    return `Sent ${msg_type} to ${to}`;
  }

  read_inbox(name: string): Array<Record<string, unknown>> {
    const inbox_path = join(this.dir, `${name}.jsonl`);
    if (!existsSync(inbox_path)) {
      return [];
    }
    const messages: Array<Record<string, unknown>> = [];
    const content = readFileSync(inbox_path, "utf8").trim();
    for (const line of content.split(/\r?\n/)) {
      if (line) {
        messages.push(JSON.parse(line) as Record<string, unknown>);
      }
    }
    writeFileSync(inbox_path, "", "utf8");
    return messages;
  }

  broadcast(sender: string, content: string, teammates: string[]): string {
    let count = 0;
    for (const name of teammates) {
      if (name !== sender) {
        this.send(sender, name, content, "broadcast");
        count += 1;
      }
    }
    return `Broadcast to ${count} teammates`;
  }
}

const BUS = new MessageBus(INBOX_DIR);

// -- TeammateManager: persistent named agents with config.json --
class TeammateManager {
  dir: string;
  config_path: string;
  config: {
    team_name: string;
    members: Array<{ name: string; role: string; status: string }>;
  };
  threads: Record<string, Promise<void>>;

  constructor(team_dir: string) {
    this.dir = team_dir;
    mkdirSync(this.dir, { recursive: true });
    this.config_path = join(this.dir, "config.json");
    this.config = this._load_config();
    this.threads = {};
  }

  _load_config(): {
    team_name: string;
    members: Array<{ name: string; role: string; status: string }>;
  } {
    if (existsSync(this.config_path)) {
      return JSON.parse(readFileSync(this.config_path, "utf8")) as {
        team_name: string;
        members: Array<{ name: string; role: string; status: string }>;
      };
    }
    return { team_name: "default", members: [] };
  }

  _save_config(): void {
    writeFileSync(this.config_path, `${JSON.stringify(this.config, null, 2)}\n`, "utf8");
  }

  _find_member(name: string): { name: string; role: string; status: string } | null {
    for (const member of this.config.members) {
      if (member.name === name) {
        return member;
      }
    }
    return null;
  }

  spawn(name: string, role: string, prompt: string): string {
    let member = this._find_member(name);
    if (member) {
      if (!["idle", "shutdown"].includes(member.status)) {
        return `Error: '${name}' is currently ${member.status}`;
      }
      member.status = "working";
      member.role = role;
    } else {
      member = { name, role, status: "working" };
      this.config.members.push(member);
    }
    this._save_config();
    const thread = this._teammate_loop(name, role, prompt);
    this.threads[name] = thread;
    void thread;
    return `Spawned '${name}' (role: ${role})`;
  }

  async _teammate_loop(name: string, role: string, prompt: string): Promise<void> {
    const sys_prompt = `You are '${name}', role: ${role}, at ${WORKDIR}. Use send_message to communicate. Complete your task.`;
    const messages: Array<{ role: "user" | "assistant"; content: unknown }> = [
      { role: "user", content: prompt },
    ];
    const tools = this._teammate_tools();

    for (let i = 0; i < 50; i += 1) {
      const inbox = BUS.read_inbox(name);
      for (const msg of inbox) {
        messages.push({ role: "user", content: JSON.stringify(msg) });
      }

      let response;
      try {
        response = await client.messages.create({
          model: MODEL,
          system: sys_prompt,
          messages: messages as never,
          tools: tools as never,
          max_tokens: 8000,
        });
      } catch {
        break;
      }

      messages.push({ role: "assistant", content: response.content });
      if (response.stop_reason !== "tool_use") {
        break;
      }

      const results: Array<Record<string, unknown>> = [];
      for (const block of response.content as unknown[]) {
        if (
          !block ||
          typeof block !== "object" ||
          (block as { type?: string }).type !== "tool_use"
        ) {
          continue;
        }

        const tool_use = block as {
          id: string;
          name: string;
          input: Record<string, unknown>;
        };
        const output = this._exec(name, tool_use.name, tool_use.input);
        console.log(`  [${name}] ${tool_use.name}: ${String(output).slice(0, 120)}`);
        results.push({
          type: "tool_result",
          tool_use_id: tool_use.id,
          content: String(output),
        });
      }
      messages.push({ role: "user", content: results });
    }

    const member = this._find_member(name);
    if (member && member.status !== "shutdown") {
      member.status = "idle";
      this._save_config();
    }
  }

  _exec(sender: string, tool_name: string, args: Record<string, unknown>): string {
    // these base tools are unchanged from s02
    if (tool_name === "bash") {
      return _run_bash(String(args.command ?? ""));
    }
    if (tool_name === "read_file") {
      return _run_read(String(args.path ?? ""));
    }
    if (tool_name === "write_file") {
      return _run_write(String(args.path ?? ""), String(args.content ?? ""));
    }
    if (tool_name === "edit_file") {
      return _run_edit(
        String(args.path ?? ""),
        String(args.old_text ?? ""),
        String(args.new_text ?? "")
      );
    }
    if (tool_name === "send_message") {
      return BUS.send(
        sender,
        String(args.to ?? ""),
        String(args.content ?? ""),
        String(args.msg_type ?? "message")
      );
    }
    if (tool_name === "read_inbox") {
      return JSON.stringify(BUS.read_inbox(sender), null, 2);
    }
    return `Unknown tool: ${tool_name}`;
  }

  _teammate_tools(): Array<Record<string, unknown>> {
    // these base tools are unchanged from s02
    return [
      {
        name: "bash",
        description: "Run a shell command.",
        input_schema: {
          type: "object",
          properties: { command: { type: "string" } },
          required: ["command"],
        },
      },
      {
        name: "read_file",
        description: "Read file contents.",
        input_schema: {
          type: "object",
          properties: {
            path: { type: "string" }
          },
          required: ["path"],
        },
      },
      {
        name: "write_file",
        description: "Write content to file.",
        input_schema: {
          type: "object",
          properties: {
            path: { type: "string" },
            content: { type: "string" },
          },
          required: ["path", "content"],
        },
      },
      {
        name: "edit_file",
        description: "Replace exact text in file.",
        input_schema: {
          type: "object",
          properties: {
            path: { type: "string" },
            old_text: { type: "string" },
            new_text: { type: "string" },
          },
          required: ["path", "old_text", "new_text"],
        },
      },
      {
        name: "send_message",
        description: "Send message to a teammate.",
        input_schema: {
          type: "object",
          properties: {
            to: { type: "string" },
            content: { type: "string" },
            msg_type: { type: "string", enum: [...VALID_MSG_TYPES] },
          },
          required: ["to", "content"],
        },
      },
      {
        name: "read_inbox",
        description: "Read and drain your inbox.",
        input_schema: {
          type: "object",
          properties: {},
        },
      },
    ];
  }

  list_all(): string {
    if (!this.config.members.length) {
      return "No teammates.";
    }
    const lines = [`Team: ${this.config.team_name}`];
    for (const member of this.config.members) {
      lines.push(`  ${member.name} (${member.role}): ${member.status}`);
    }
    return lines.join("\n");
  }

  member_names(): string[] {
    return this.config.members.map((member) => member.name);
  }
}

const TEAM = new TeammateManager(TEAM_DIR);

// -- Base tool implementations (these base tools are unchanged from s02) --
function _safe_path(p: string): string {
  const path = resolve(WORKDIR, p);
  const rel = relative(WORKDIR, path);
  if (rel.startsWith("..")) {
    throw new Error(`Path escapes workspace: ${p}`);
  }
  return path;
}

function _run_bash(command: string): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot"];
  if (dangerous.some((item) => command.includes(item))) {
    return "Error: Dangerous command blocked";
  }
  try {
    const result = spawnSync(command, {
      shell: true,
      cwd: WORKDIR,
      encoding: "utf8",
      timeout: 120_000,
    });
    if (result.error) {
      if ((result.error as NodeJS.ErrnoException).code === "ETIMEDOUT") {
        return "Error: Timeout (120s)";
      }
      return `Error: ${result.error instanceof Error ? result.error.message : String(result.error)}`;
    }
    const out = `${result.stdout ?? ""}${result.stderr ?? ""}`.trim();
    return out ? out.slice(0, 50_000) : "(no output)";
  } catch (error) {
    return `Error: ${error instanceof Error ? error.message : String(error)}`;
  }
}

function _run_read(path: string, limit?: number): string {
  try {
    let lines = readFileSync(_safe_path(path), "utf8").split(/\r?\n/);
    if (limit && limit < lines.length) {
      lines = lines.slice(0, limit).concat(`... (${lines.length - limit} more)`);
    }
    return lines.join("\n").slice(0, 50_000);
  } catch (error) {
    return `Error: ${error instanceof Error ? error.message : String(error)}`;
  }
}

function _run_write(path: string, content: string): string {
  try {
    const fp = _safe_path(path);
    mkdirSync(dirname(fp), { recursive: true });
    writeFileSync(fp, content, "utf8");
    return `Wrote ${content.length} bytes`;
  } catch (error) {
    return `Error: ${error instanceof Error ? error.message : String(error)}`;
  }
}

function _run_edit(path: string, old_text: string, new_text: string): string {
  try {
    const fp = _safe_path(path);
    const content = readFileSync(fp, "utf8");
    if (!content.includes(old_text)) {
      return `Error: Text not found in ${path}`;
    }
    writeFileSync(fp, content.replace(old_text, new_text), "utf8");
    return `Edited ${path}`;
  } catch (error) {
    return `Error: ${error instanceof Error ? error.message : String(error)}`;
  }
}

// -- Lead tool dispatch (9 tools) --
const TOOL_HANDLERS = {
  bash: (args: Record<string, unknown>) => _run_bash(String(args.command ?? "")),
