  write_file: (args: Record<string, unknown>) =>
    _run_write(String(args.path ?? ""), String(args.content ?? "")),
  edit_file: (args: Record<string, unknown>) =>
    _run_edit(
      String(args.path ?? ""),
      String(args.old_text ?? ""),
