    ),
  read_inbox: (_args: Record<string, unknown>) =>
    JSON.stringify(BUS.read_inbox("lead"), null, 2),
  broadcast: (args: Record<string, unknown>) =>
    BUS.broadcast("lead", String(args.content ?? ""), TEAM.member_names()),
};

